"use strict";(self.webpackChunkdeveloper_playcanvas_com=self.webpackChunkdeveloper_playcanvas_com||[]).push([["88043"],{14642(t){t.exports=JSON.parse('{"tag":{"label":"input","permalink":"/tags/input","allTagsPath":"/tags","count":33,"items":[{"id":"tutorials/360-lookaround-camera","title":"360 lookaround camera","description":"Use mouse and touch to rotate the camera and look around a scene for a panoramic or first-person style viewer.","permalink":"/tutorials/360-lookaround-camera"},{"id":"tutorials/keyboard-input","title":"Basic Keyboard Input","description":"Use the Keyboard API to detect key presses and held keys for gameplay actions and simple interactions.","permalink":"/tutorials/keyboard-input"},{"id":"tutorials/mouse-input","title":"Basic Mouse Input","description":"Use the Mouse API to read movement, button presses, and consistent screen coordinates across browsers for interactive controls.","permalink":"/tutorials/mouse-input"},{"id":"tutorials/basic-touch-input","title":"Basic touch input","description":"Handle touch events to drag and move on-screen objects for a minimal mobile-first interaction sample.","permalink":"/tutorials/basic-touch-input"},{"id":"tutorials/detecting-a-double-click","title":"Detecting a double click","description":"Detect double-clicks with timing logic and use them to move the camera or trigger actions on desktop browsers.","permalink":"/tutorials/detecting-a-double-click"},{"id":"tutorials/detecting-a-double-tap","title":"Detecting a double tap","description":"Recognize double-tap gestures on touchscreens separately from single taps for mobile-friendly interactions.","permalink":"/tutorials/detecting-a-double-tap"},{"id":"tutorials/detecting-a-long-press","title":"Detecting a long press","description":"Measure press duration on touch or mouse to fire actions after the user holds on an element long enough.","permalink":"/tutorials/detecting-a-long-press"},{"id":"tutorials/entity-picking-using-physics","title":"Entity picking using physics","description":"Cast physics raycasts from the pointer to hit colliders and select entities under the cursor in 3D.","permalink":"/tutorials/entity-picking-using-physics"},{"id":"tutorials/entity-picking-without-physics","title":"Entity picking without physics","description":"Pick meshes using math ray tests instead of the physics engine to avoid extra runtime weight in published builds.","permalink":"/tutorials/entity-picking-without-physics"},{"id":"tutorials/first-person-movement","title":"First Person Movement","description":"Implement first-person movement with rigidbody forces, mouse look, and an optional child camera rig.","permalink":"/tutorials/first-person-movement"},{"id":"tutorials/first-person-shooter-starter-kit","title":"First Person Shooter Starter Kit","description":"Extend first-person controls with jumping and navigation as a starter for FPS-style movement prototypes.","permalink":"/tutorials/first-person-shooter-starter-kit"},{"id":"tutorials/flaming-fireball","title":"Flaming fireball","description":"Drive a particle fireball that follows the pointer for a simple magical projectile and trail effect.","permalink":"/tutorials/flaming-fireball"},{"id":"tutorials/information-hotspots","title":"Information hotspots","description":"Place clickable hotspots in the 3D view that open info panels using raycasts and screen overlays.","permalink":"/tutorials/information-hotspots"},{"id":"tutorials/locking-the-mouse","title":"Locking the mouse","description":"Request pointer lock on click to capture the mouse for first-person look, hiding the cursor while movement drives the camera.","permalink":"/tutorials/locking-the-mouse"},{"id":"tutorials/multitouch-input","title":"Multitouch input","description":"Track every active touch point and visualize multitouch gestures by drawing lines between fingers on the screen.","permalink":"/tutorials/multitouch-input"},{"id":"tutorials/orbit-camera","title":"Orbit camera","description":"Implement an orbit camera with mouse and touch, including scroll-wheel zoom and pinch-to-zoom around a focal entity.","permalink":"/tutorials/orbit-camera"},{"id":"tutorials/pan-camera-to-target","title":"Pan Camera to Target","description":"Smoothly move and aim the camera toward a world-space target so clicks or events frame important locations in the scene.","permalink":"/tutorials/pan-camera-to-target"},{"id":"tutorials/physics-raycasting-by-tag","title":"Physics raycasting by tag","description":"Filter physics raycast hits by entity tags so picking ignores the wrong colliders and only selects intended objects.","permalink":"/tutorials/physics-raycasting-by-tag"},{"id":"tutorials/place-an-entity-with-physics","title":"Place an entity with physics","description":"Spawn physics-enabled props at clicked world positions using raycasts against the ground so new bodies collide correctly.","permalink":"/tutorials/place-an-entity-with-physics"},{"id":"tutorials/place-entity-without-physics","title":"Place entity without physics","description":"Instantiate decorative entities at clicked ground positions using math and raycasts without adding rigidbody simulation.","permalink":"/tutorials/place-entity-without-physics"},{"id":"tutorials/point-and-click-movement","title":"Point and click movement","description":"Move a character or object toward clicked ground positions using screen-to-world raycasts for simple navigation.","permalink":"/tutorials/point-and-click-movement"},{"id":"tutorials/raycast-with-camera-viewports","title":"Raycast with Camera Viewports","description":"Convert pointer coordinates into per-camera rays when using split viewports so picking hits the correct 3D region in each pane.","permalink":"/tutorials/raycast-with-camera-viewports"},{"id":"tutorials/rotating-objects-with-mouse","title":"Rotating Objects with Mouse","description":"Orbit or spin an object by mapping mouse drag deltas in screen space to rotation quaternions or euler angles each frame.","permalink":"/tutorials/rotating-objects-with-mouse"},{"id":"tutorials/simple-shape-raycasting","title":"Simple shape raycasting","description":"Cast a physics ray from the camera through the pointer to detect which entity or shape sits under the cursor.","permalink":"/tutorials/simple-shape-raycasting"},{"id":"tutorials/third-person-controller","title":"Third Person Controller","description":"Follow a controllable character with a chase camera while handling input and physics for a basic third-person movement rig.","permalink":"/tutorials/third-person-controller"},{"id":"tutorials/touch-joypad","title":"Touchscreen Joypad Controls","description":"Add a customizable on-screen twin-stick style joypad with PlayCanvas UI elements for mobile character control.","permalink":"/tutorials/touch-joypad"},{"id":"tutorials/webxr-ar-raycasting-shapes","title":"WebXR AR Raycasting Shapes","description":"Raycast against PlayCanvas meshes during an AR session so taps on virtual shapes work alongside the passthrough camera view.","permalink":"/tutorials/webxr-ar-raycasting-shapes"},{"id":"tutorials/webxr-controllerhand-models","title":"WebXR Controller/Hand Models","description":"Load WebXR input profile meshes for controllers and hands so tracked hardware matches each vendor silhouette in VR.","permalink":"/tutorials/webxr-controllerhand-models"},{"id":"tutorials/webxr-hands","title":"WebXR Hands","description":"Read WebXR hand-tracking joint poses and mirror finger motion in the scene for natural direct manipulation without controllers.","permalink":"/tutorials/webxr-hands"},{"id":"tutorials/webxr-realistic-hands","title":"WebXR Realistic Hands","description":"Skin tracked hand joints with detailed meshes and materials so articulated fingers read clearly in immersive VR sessions.","permalink":"/tutorials/webxr-realistic-hands"},{"id":"tutorials/webxr-tracked-controllers","title":"WebXR Tracked Controllers","description":"Follow six-DoF controllers in VR with starter code for poses, buttons, and haptics inside a PlayCanvas WebXR template.","permalink":"/tutorials/webxr-tracked-controllers"},{"id":"tutorials/webxr-ray-input","title":"WebXR UI Interaction","description":"Point WebXR laser pointers or gaze at screen-space UI and handle clicks across desktop, mobile, and headset browsers.","permalink":"/tutorials/webxr-ray-input"},{"id":"tutorials/webxr-vr-lab","title":"WebXR VR Lab","description":"Explore a maintained VR sandbox that demonstrates scalable interaction patterns and responsive layouts across XR devices.","permalink":"/tutorials/webxr-vr-lab"}],"unlisted":false}}')}}]);